protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator (e.g. "123" instead of "Product|123").
        // Existing documents have the compound format; this preserves compatibility.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // EF Core 9: HasIndex now throws for Cosmos entities. Removed.
    // Manage indexing via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

